attempts.prompt:
The following Dafny program has a correct implementation and specification, but verification fails because some `assert` statements are missing. The program verified successfully before these assertions were removed.

RULES — read carefully:
1. Add `assert` statements to make `dafny verify` pass.
2. You may add helper lemmas or ghost functions if needed.
3. You MUST NOT modify ANY existing code. Do not change variable names, assignments, control flow, loop bodies, if/else branches, return statements, or any expression.
4. You MUST NOT modify ANY formal specification. Do not change requires, ensures, invariant, decreases, function bodies, or predicate bodies.
5. Any modification to existing code or specifications will be automatically detected and rejected. We compare the AST of your output against the original — only added assert statements and new lemma/function definitions are permitted.

Return the complete Dafny program with your added assertions inside <DAFNY_CODE> tags.

```dafny
ghost function CountChar(s: string, c: char): int
  decreases |s|
{
  if |s| == 0 then 0
  else CountChar(s[..|s|-1], c) + (if s[|s|-1] == c then 1 else 0)
}

ghost predicate IsGood(s: string)
{
  CountChar(s, '0') != CountChar(s, '1')
}

ghost predicate IsBinaryString(s: string)
{
  forall i | 0 <= i < |s| :: s[i] == '0' || s[i] == '1'
}

ghost function Flatten(parts: seq<string>): string
  decreases |parts|
{
  if |parts| == 0 then ""
  else Flatten(parts[..|parts|-1]) + parts[|parts|-1]
}

ghost predicate AllGood(parts: seq<string>)
{
  forall i | 0 <= i < |parts| :: IsGood(parts[i])
}

lemma CountCharSum(s: string)
  requires IsBinaryString(s)
  ensures CountChar(s, '0') + CountChar(s, '1') == |s|
  decreases |s|
{
  if |s| > 0 {
    CountCharSum(s[..|s|-1]);
  }
}

lemma FlattenSingleton(x: string)
  ensures Flatten([x]) == x
{
  assert [x][..0] == [];
  assert [x][0] == x;
}

lemma FlattenPair(a: string, b: string)
  ensures Flatten([a, b]) == a + b
{
  assert [a, b][..1] == [a];
  assert [a, b][1] == b;
  FlattenSingleton(a);
}

method KeanuReeves(s: string) returns (k: int, parts: seq<string>)
  requires |s| > 0
  requires IsBinaryString(s)
  ensures k == |parts|
  ensures k == 1 || k == 2
  ensures Flatten(parts) == s
  ensures AllGood(parts)
  ensures k == 1 <==> IsGood(s)
{
  var zeros := 0;
  var ones := 0;
  var i := 0;
  while i < |s|
    invariant 0 <= i <= |s|
    invariant zeros == CountChar(s[..i], '0')
    invariant ones == CountChar(s[..i], '1')
  {

    if s[i] == '0' {
      zeros := zeros + 1;
    } else {
      ones := ones + 1;
    }
    i := i + 1;
  }

  if zeros != ones {
    k := 1;
    parts := [s];
    FlattenSingleton(s);
  } else {
    k := 2;
    var first := s[..|s| - 1];
    var second := [s[|s| - 1]];
    parts := [first, second];

    // Flatten proof
    assert first + second == s;
    FlattenPair(first, second);

    // first is good: odd-length binary string can't have equal counts
    CountCharSum(s);
    CountCharSum(first);
    assert IsGood(first);

    // second is good: single character
    assert IsGood(second);
  }
}

```

